class Solution {
    public int longestPalindrome(String s, String t) {
        int n = s.length(), m = t.length();
        int max = 0;
        // Case 1: palindrome entirely in s
        for (int l = 0; l < n; l++) {
            for (int r = l; r < n; r++) {
                if (isPal(s, l, r)) max = Math.max(max, r - l + 1);
            }
        }
        // Case 2: palindrome entirely in t
        for (int l = 0; l < m; l++) {
            for (int r = l; r < m; r++) {
                if (isPal(t, l, r)) max = Math.max(max, r - l + 1);
            }
        }
        // Case 3: palindrome formed by suffix of s + prefix of t
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                int len = 0;
                while (i - len >= 0 && j + len < m && s.charAt(i - len) == t.charAt(j + len)) {
                    len++;
                }
                if (len > 0) {
                    int left = i - len + 1, right = j + len - 1;
                    int l = left - 1, r = right + 1;
                    while (l >= 0 && r < m && s.charAt(l) == t.charAt(r)) {
                        l--; r++;
                    }
                    max = Math.max(max, (r - l - 1) + len);
                }
            }
        }
        // Case 4: palindrome formed by prefix of s + suffix of t
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                int len = 0;
                while (i + len < n && j - len >= 0 && s.charAt(i + len) == t.charAt(j - len)) {
                    len++;
                }
                if (len > 0) {
                    int left = i + len - 1, right = j - len + 1;
                    int l = left + 1, r = right - 1;
                    while (l < n && r >= 0 && s.charAt(l) == t.charAt(r)) {
                        l++; r--;
                    }
                    max = Math.max(max, (l - r - 1) + len);
                }
            }
        }
        return max == 0 ? 1 : max;
    }
    private boolean isPal(String str, int l, int r) {
        while (l < r) {
            if (str.charAt(l++) != str.charAt(r--)) return false;
        }
        return true;
    }
}
